import { fmt } from "./parseItem";

const SANS = "Unbounded, system-ui, -apple-system, BlinkMacSystemFont, Segoe UI, sans-serif";
const MONO = "Geist Mono, ui-monospace, SFMono-Regular, Menlo, Consolas, monospace";

function themeColors() {
  const isDark = document.documentElement.classList.contains("dark");
  // Refined palette based on OKLCH mappings for premium dashboard feel
  return {
    isDark,
    bg: isDark ? "#09090b" : "#fafafa",
    surface: isDark ? "#18181b" : "#f4f4f5",
    text: isDark ? "#fafafa" : "#09090b",
    muted: isDark ? "#a1a1aa" : "#71717a",
    subtle: isDark ? "#52525b" : "#a1a1aa",
    accent: isDark ? "#10b981" : "#059669", // Emerald
    accentSoft: isDark ? "#064e3b" : "#dcfce7",
    warning: isDark ? "#f59e0b" : "#d97706", // Amber
    error: isDark ? "#ef4444" : "#dc2626", // Red
    border: isDark ? "rgba(255,255,255,0.06)" : "rgba(0,0,0,0.06)",
    grid: isDark ? "rgba(255,255,255,0.03)" : "rgba(0,0,0,0.03)",
    glowPrimary: isDark ? "rgba(16,185,129,0.12)" : "rgba(16,185,129,0.08)",
    glowSecondary: isDark ? "rgba(245,158,11,0.08)" : "rgba(245,158,11,0.05)",
  };
}

const VARIANTS = {
  item: { width: 1200, height: 630, compose: composeItemCard },
  compact: { width: 1080, height: 1080, compose: composeCompactCard },
};

export const EXPORT_VARIANTS = Object.keys(VARIANTS);

function roundRect(ctx, x, y, w, h, r) {
  const radius = Math.min(r, w / 2, h / 2);
  ctx.beginPath();
  ctx.moveTo(x + radius, y);
  ctx.arcTo(x + w, y, x + w, y + h, radius);
  ctx.arcTo(x + w, y + h, x, y + h, radius);
  ctx.arcTo(x, y + h, x, y, radius);
  ctx.arcTo(x, y, x + w, y, radius);
  ctx.closePath();
}

function fillRoundRect(ctx, x, y, w, h, r, fill, stroke = null) {
  roundRect(ctx, x, y, w, h, r);
  ctx.fillStyle = fill;
  ctx.fill();
  if (stroke) {
    ctx.strokeStyle = stroke;
    ctx.lineWidth = 1;
    ctx.stroke();
  }
}

function drawLabel(ctx, text, x, y, color) {
  ctx.font = `700 11px ${MONO}`;
  ctx.fillStyle = color;
  ctx.fillText(String(text || "").toUpperCase(), x, y);
}

function drawTextLines(ctx, text, x, y, maxWidth, lineHeight, maxLines) {
  const words = String(text || "").split(/\s+/).filter(Boolean);
  const lines = [];
  let line = "";
  let consumed = 0;
  for (const word of words) {
    const next = line ? `${line} ${word}` : word;
    if (ctx.measureText(next).width <= maxWidth || !line) {
      line = next;
      consumed += 1;
      continue;
    }
    lines.push(line);
    line = word;
    consumed += 1;
    if (lines.length >= maxLines) break;
  }
  if (line && lines.length < maxLines) lines.push(line);
  if (lines.length === maxLines && consumed < words.length) {
    let last = lines[lines.length - 1];
    while (ctx.measureText(`${last}...`).width > maxWidth && last.length > 1) {
      last = last.slice(0, -1);
    }
    lines[lines.length - 1] = `${last}...`;
  }
  lines.forEach((value, index) => ctx.fillText(value, x, y + index * lineHeight));
  return lines.length * lineHeight;
}

function drawChip(ctx, text, x, y, color, bg, border) {
  ctx.font = `800 18px ${MONO}`;
  const width = Math.ceil(ctx.measureText(text).width) + 18;
  fillRoundRect(ctx, x, y - 22, width, 30, 4, bg, border);
  ctx.fillStyle = color;
  ctx.fillText(text, x + 9, y);
  return width;
}

function drawGrid(ctx, width, height, color) {
  ctx.save();
  ctx.strokeStyle = color;
  ctx.lineWidth = 1;
  const size = 40;
  for (let x = 0; x <= width; x += size) {
    ctx.beginPath();
    ctx.moveTo(x, 0);
    ctx.lineTo(x, height);
    ctx.stroke();
  }
  for (let y = 0; y <= height; y += size) {
    ctx.beginPath();
    ctx.moveTo(0, y);
    ctx.lineTo(width, y);
    ctx.stroke();
  }
  ctx.restore();
}

function drawGlow(ctx, x, y, radius, color, width, height) {
  const gradient = ctx.createRadialGradient(x, y, 0, x, y, radius);
  gradient.addColorStop(0, color);
  gradient.addColorStop(1, "transparent");
  ctx.save();
  ctx.globalCompositeOperation = "screen";
  ctx.fillStyle = gradient;
  ctx.fillRect(0, 0, width, height);
  ctx.restore();
}

function fmtStamp(ms) {
  const d = new Date(ms || Date.now());
  const yyyy = d.getUTCFullYear();
  const mm = String(d.getUTCMonth() + 1).padStart(2, "0");
  const dd = String(d.getUTCDate()).padStart(2, "0");
  const hh = String(d.getUTCHours()).padStart(2, "0");
  const mi = String(d.getUTCMinutes()).padStart(2, "0");
  return `${yyyy}-${mm}-${dd} ${hh}:${mi} UTC`;
}

function trendLabel(trend, t) {
  if (trend === "up") return { label: "Rising", color: t.green };
  if (trend === "down") return { label: "Falling", color: t.red };
  return { label: "Stable", color: t.subtle };
}

function drawSparkline(ctx, series, median, x, y, w, h, t) {
  fillRoundRect(ctx, x, y, w, h, 12, t.surface, t.border);
  const data = Array.isArray(series) ? series.filter((p) => Number(p?.v) > 0) : [];
  if (data.length < 2) {
    ctx.font = `700 13px ${MONO}`;
    ctx.fillStyle = t.subtle;
    ctx.textAlign = "center";
    ctx.fillText(data.length === 1 ? "1 DATA POINT" : "INSUFFICIENT DATA", x + w / 2, y + h / 2);
    ctx.textAlign = "left";
    return;
  }

  const padL = 64;
  const padR = 32;
  const padT = 40;
  const padB = 48;
  const innerW = w - padL - padR;
  const innerH = h - padT - padB;
  const values = data.map((p) => Number(p.v));
  let min = Math.min(...values, Number(median || Infinity));
  let max = Math.max(...values, Number(median || 0));
  const span = max - min || 1;
  min -= span * 0.1;
  max += span * 0.1;
  const range = max - min || 1;

  const points = data.map((p, index) => [
    x + padL + (innerW * index) / (data.length - 1),
    y + padT + innerH - ((Number(p.v) - min) / range) * innerH,
  ]);

  ctx.save();
  ctx.strokeStyle = t.border;
  ctx.fillStyle = t.muted;
  ctx.font = `500 10px ${MONO}`;
  
  // Grid lines
  [min, min + range / 2, max].forEach((tick) => {
    const ty = y + padT + innerH - ((tick - min) / range) * innerH;
    ctx.beginPath();
    ctx.moveTo(x + padL, ty);
    ctx.lineTo(x + padL + innerW, ty);
    ctx.stroke();
    ctx.textAlign = "right";
    ctx.fillText(fmt(tick), x + padL - 12, ty + 3);
  });
  ctx.textAlign = "left";

  if (median > 0) {
    const medianY = y + padT + innerH - ((median - min) / range) * innerH;
    ctx.strokeStyle = t.warning;
    ctx.setLineDash([4, 4]);
    ctx.lineWidth = 1;
    ctx.beginPath();
    ctx.moveTo(x + padL, medianY);
    ctx.lineTo(x + padL + innerW, medianY);
    ctx.stroke();
    ctx.setLineDash([]);
  }

  // Area fill
  ctx.beginPath();
  points.forEach(([px, py], index) => {
    if (index === 0) ctx.moveTo(px, py);
    else ctx.lineTo(px, py);
  });
  const last = points[points.length - 1];
  const first = points[0];
  ctx.lineTo(last[0], y + padT + innerH);
  ctx.lineTo(first[0], y + padT + innerH);
  ctx.closePath();
  const fill = ctx.createLinearGradient(0, y + padT, 0, y + padT + innerH);
  fill.addColorStop(0, t.accent + "33");
  fill.addColorStop(1, "transparent");
  ctx.fillStyle = fill;
  ctx.fill();

  // Line
  ctx.beginPath();
  points.forEach(([px, py], index) => {
    if (index === 0) ctx.moveTo(px, py);
    else ctx.lineTo(px, py);
  });
  ctx.strokeStyle = t.accent;
  ctx.lineWidth = 2.5;
  ctx.lineJoin = "round";
  ctx.lineCap = "round";
  ctx.stroke();

  // Points
  const lastP = points[points.length - 1];
  ctx.fillStyle = t.accent;
  ctx.beginPath();
  ctx.arc(lastP[0], lastP[1], 4.5, 0, Math.PI * 2);
  ctx.fill();
  ctx.strokeStyle = t.surface;
  ctx.lineWidth = 2;
  ctx.stroke();

  // Date labels
  const labelDate = (p) => new Date(p.ts || p.t || Date.now()).toLocaleDateString(undefined, { month: "short", day: "numeric" });
  ctx.fillStyle = t.subtle;
  ctx.font = `600 10px ${MONO}`;
  ctx.textAlign = "center";
  ctx.fillText(labelDate(data[0]), points[0][0], y + h - 16);
  ctx.fillText(labelDate(data[Math.floor(data.length / 2)]), points[Math.floor(points.length / 2)][0], y + h - 16);
  ctx.fillText(labelDate(data[data.length - 1]), lastP[0], y + h - 16);
  ctx.restore();
}

function drawTopSellers(ctx, sellers, y, t) {
  drawLabel(ctx, "Market liquidity", 56, y, t.muted);
  const list = Array.isArray(sellers) ? sellers.slice(0, 3) : [];
  if (list.length === 0) {
    ctx.font = `600 14px ${SANS}`;
    ctx.fillStyle = t.subtle;
    ctx.fillText("No active listings recorded.", 56, y + 44);
    return;
  }

  const cardW = 356;
  list.forEach((seller, index) => {
    const x = 56 + index * (cardW + 12);
    fillRoundRect(ctx, x, y + 18, cardW, 64, 10, t.surface, t.border);
    ctx.font = `800 11px ${MONO}`;
    ctx.fillStyle = t.subtle;
    ctx.fillText(`#${index + 1}`, x + 16, y + 55);

    ctx.font = `800 15px ${SANS}`;
    ctx.fillStyle = t.text;
    drawTextLines(ctx, seller.name || "Unknown", x + 48, y + 43, 170, 16, 1);

    const label = seller.label || "Neutral";
    const labelColor = label === "Flagged" ? t.error : label === "Suspicious" ? t.warning : label === "Trustworthy" ? t.accent : t.muted;
    ctx.font = `700 9px ${MONO}`;
    ctx.fillStyle = labelColor;
    ctx.fillText(label.toUpperCase(), x + 48, y + 63);

    ctx.font = `900 17px ${MONO}`;
    ctx.fillStyle = t.accent;
    ctx.textAlign = "right";
    ctx.fillText(fmt(seller.unitPrice || 0), x + cardW - 16, y + 56);
    ctx.textAlign = "left";
  });
}

function drawHeader(ctx, data, width, t) {
  ctx.save();
  ctx.font = `900 12px ${MONO}`;
  ctx.fillStyle = t.accent;
  ctx.beginPath();
  ctx.arc(62, 46, 4, 0, Math.PI * 2);
  ctx.fill();
  
  ctx.fillText("CMI LIVE", 74, 50);
  
  ctx.fillStyle = t.subtle;
  ctx.textAlign = "right";
  ctx.font = `700 11px ${MONO}`;
  ctx.fillText(fmtStamp(data.generatedAt), width - 56, 50);
  ctx.restore();
}

function drawFooter(ctx, width, height, t) {
  ctx.save();
  ctx.font = `800 10px ${MONO}`;
  ctx.fillStyle = t.subtle;
  ctx.fillText("CASTIA MARKET INSIGHT", 56, height - 24);
  
  ctx.textAlign = "right";
  ctx.fillStyle = t.muted;
  ctx.fillText("DATA AGGREGATED BY LEKTO_", width - 56, height - 24);
  ctx.restore();
}

function composeItemCard(ctx, data, width, height) {
  const t = themeColors();
  drawHeader(ctx, data, width, t);

  const category = `${data.category || "General"}${data.tier > 0 ? ` · TIER ${data.tier}` : ""}`;
  drawLabel(ctx, category, 56, 124, t.accent);

  ctx.font = `900 58px ${SANS}`;
  ctx.fillStyle = t.text;
  ctx.letterSpacing = "-0.02em";
  const titleHeight = drawTextLines(ctx, data.name || "Unknown Item", 56, 175, 540, 62, 2);
  ctx.letterSpacing = "normal";

  let chipX = 56;
  const chipY = 195 + Math.min(titleHeight, 124);
  if (data.tier > 0) {
    chipX += drawChip(ctx, `T${data.tier}`, chipX, chipY, t.warning, t.warning + "1A", t.warning + "33") + 10;
  }
  for (const modifier of (data.modifiers || []).slice(0, 3)) {
    chipX += drawChip(ctx, String(modifier).toUpperCase(), chipX, chipY, t.accent, t.accent + "1A", t.accent + "33") + 10;
  }

  drawLabel(ctx, "Benchmark median", 56, 330, t.muted);
  ctx.font = `900 84px ${SANS}`;
  ctx.fillStyle = t.accent;
  ctx.fillText(data.median > 0 ? fmt(data.median) : "—", 56, 415);

  const trend = trendLabel(data.trend, t);
  ctx.font = `900 16px ${MONO}`;
  ctx.fillStyle = trend.color;
  ctx.fillText(trend.label.toUpperCase(), 56, 452);

  ctx.font = `800 11px ${MONO}`;
  ctx.fillStyle = t.muted;
  ctx.fillText("CONFIDENCE", 56, 494);
  ctx.fillText("SAMPLES", 270, 494);
  
  ctx.fillStyle = data.confidence === "high" || data.confidence === "good" ? t.accent : data.confidence === "fair" ? t.warning : t.subtle;
  ctx.fillText(String(data.confidence || "n/a").toUpperCase(), 56, 516);
  ctx.fillStyle = t.text;
  ctx.fillText(String(data.samples || 0), 270, 516);

  drawLabel(ctx, `Price action · ${(data.series || []).length} pts`, 620, 124, t.muted);
  drawSparkline(ctx, data.series || [], data.median || 0, 620, 146, 524, 300, t);

  drawTopSellers(ctx, data.topSellers || [], 518, t);

  drawFooter(ctx, width, height, t);
}

function composeCompactCard(ctx, data, width, height) {
  const t = themeColors();
  drawHeader(ctx, data, width, t);

  const category = `${data.category || "General"}${data.tier > 0 ? ` · TIER ${data.tier}` : ""}`;
  drawLabel(ctx, category, 64, 140, t.accent);

  ctx.font = `900 72px ${SANS}`;
  ctx.fillStyle = t.text;
  ctx.letterSpacing = "-0.02em";
  const titleHeight = drawTextLines(ctx, data.name || "Unknown Item", 64, 206, width - 128, 78, 2);
  ctx.letterSpacing = "normal";

  let chipX = 64;
  const chipY = 225 + Math.min(titleHeight, 156);
  if (data.tier > 0) {
    chipX += drawChip(ctx, `T${data.tier}`, chipX, chipY, t.warning, t.warning + "1A", t.warning + "33") + 10;
  }
  for (const modifier of (data.modifiers || []).slice(0, 3)) {
    chipX += drawChip(ctx, String(modifier).toUpperCase(), chipX, chipY, t.accent, t.accent + "1A", t.accent + "33") + 10;
  }

  drawLabel(ctx, "Benchmark median", 64, 410, t.muted);
  ctx.font = `900 116px ${SANS}`;
  ctx.fillStyle = t.accent;
  ctx.fillText(data.median > 0 ? fmt(data.median) : "—", 64, 520);

  const trend = trendLabel(data.trend, t);
  ctx.font = `900 20px ${MONO}`;
  ctx.fillStyle = trend.color;
  ctx.fillText(trend.label.toUpperCase(), 64, 568);

  ctx.font = `800 12px ${MONO}`;
  ctx.fillStyle = t.muted;
  ctx.fillText("CONFIDENCE", 64, 616);
  ctx.fillText("SAMPLES", 320, 616);
  ctx.fillStyle = data.confidence === "high" || data.confidence === "good" ? t.accent : data.confidence === "fair" ? t.warning : t.subtle;
  ctx.fillText(String(data.confidence || "n/a").toUpperCase(), 64, 642);
  ctx.fillStyle = t.text;
  ctx.fillText(String(data.samples || 0), 320, 642);

  drawLabel(ctx, `Price action · ${(data.series || []).length} pts`, 64, 710, t.muted);
  drawSparkline(ctx, data.series || [], data.median || 0, 64, 730, width - 128, 240, t);

  drawFooter(ctx, width, height, t);
}

export function renderCastiaCardToBlob(data, { variant = "item" } = {}) {
  const v = VARIANTS[variant] || VARIANTS.item;
  return new Promise((resolve, reject) => {
    const canvas = document.createElement("canvas");
    canvas.width = v.width;
    canvas.height = v.height;
    const ctx = canvas.getContext("2d");
    if (!ctx) { reject(new Error("Canvas is unavailable")); return; }

    const t = themeColors();
    ctx.fillStyle = t.bg;
    ctx.fillRect(0, 0, v.width, v.height);
    
    // Background glows
    if (v.width >= v.height) {
      drawGlow(ctx, v.width - 200, 100, 600, t.glowPrimary, v.width, v.height);
      drawGlow(ctx, 100, v.height - 100, 500, t.glowSecondary, v.width, v.height);
    } else {
      drawGlow(ctx, v.width - 100, 100, 600, t.glowPrimary, v.width, v.height);
      drawGlow(ctx, 100, v.height - 200, 500, t.glowSecondary, v.width, v.height);
    }
    
    drawGrid(ctx, v.width, v.height, t.grid);

    v.compose(ctx, data, v.width, v.height);

    canvas.toBlob((blob) => {
      if (blob) resolve(blob);
      else reject(new Error("PNG export failed"));
    }, "image/png");
  });
}
