import { useEffect, useState, useCallback } from "react";

const BLOCKLIST_KEY = "castia.blocklist";

function storageEventName(key) {
  return `castia:${key.replace("castia.", "")}`;
}

function readSet() {
  try {
    const raw = localStorage.getItem(BLOCKLIST_KEY);
    if (!raw) return new Set();
    const arr = JSON.parse(raw);
    return new Set(Array.isArray(arr) ? arr : []);
  } catch {
    return new Set();
  }
}

function writeSet(set) {
  try {
    localStorage.setItem(BLOCKLIST_KEY, JSON.stringify(Array.from(set)));
    window.dispatchEvent(new CustomEvent(storageEventName(BLOCKLIST_KEY)));
  } catch {
    /* quota exceeded — ignore */
  }
}

export function useBlocklist() {
  const [set, setSet] = useState(() => readSet());

  useEffect(() => {
    const handler = () => {
      // Deduplicate: custom event handles same-tab updates,
      // "storage" handles other tabs. window.dispatchEvent
      // doesn't trigger "storage" on same window in standard browsers,
      // but we'll be safe.
      setSet(readSet());
    };
    window.addEventListener(storageEventName(BLOCKLIST_KEY), handler);
    window.addEventListener("storage", (e) => {
      if (e.key === BLOCKLIST_KEY) handler();
    });
    return () => {
      window.removeEventListener(storageEventName(BLOCKLIST_KEY), handler);
      window.removeEventListener("storage", handler);
    };
  }, []);

  const toggle = useCallback((seller) => {
    const next = new Set(set);
    if (next.has(seller)) next.delete(seller);
    else next.add(seller);
    writeSet(next);
    setSet(next);
    return next.has(seller);
  }, [set]);

  const has = useCallback((seller) => set.has(seller), [set]);

  const clear = useCallback(() => {
    writeSet(new Set());
    setSet(new Set());
  }, []);

  return { sellers: Array.from(set), has, toggle, clear, count: set.size };
}