// useServiceWorkerUpdate — detects when a new service worker is
// installed and waiting. Returns { needsUpdate, applyUpdate } so the
// UI can show a 'new version available' banner and trigger a reload.
//
// Listens for:
//   - An already-waiting worker on mount.
//   - `updatefound` during the initial registration.
//   - `controllerchange` (the waiting worker took over).

import { useEffect, useState, useCallback } from "react";

export function useServiceWorkerUpdate() {
  const [waitingWorker, setWaitingWorker] = useState(null);
  const [needsUpdate, setNeedsUpdate] = useState(false);

  const onUpdateAvailable = useCallback((registration) => {
    const w = registration.waiting;
    if (w) {
      setWaitingWorker(w);
      setNeedsUpdate(true);
    }
  }, []);

  useEffect(() => {
    if (typeof navigator === "undefined" || !("serviceWorker" in navigator)) return;
    if (process.env.NODE_ENV !== "production") return;

    const setupRegistration = async () => {
      const reg = await navigator.serviceWorker.getRegistration();
      if (!reg) return;

      // Already waiting when we mount.
      if (reg.waiting) onUpdateAvailable(reg);

      // Watch for the next install cycle.
      reg.addEventListener("updatefound", () => {
        const installing = reg.installing;
        if (!installing) return;
        installing.addEventListener("statechange", () => {
          if (installing.state === "installed" && reg.waiting) {
            onUpdateAvailable(reg);
          }
        });
      });
    };

    setupRegistration();

    // After a new worker takes over, check for yet another waiting worker.
    const onControllerChange = () => {
      navigator.serviceWorker.getRegistration().then((reg) => {
        if (reg && reg.waiting) onUpdateAvailable(reg);
      });
    };
    navigator.serviceWorker.addEventListener("controllerchange", onControllerChange);

    return () => {
      navigator.serviceWorker.removeEventListener("controllerchange", onControllerChange);
    };
  }, [onUpdateAvailable]);

  const applyUpdate = useCallback(() => {
    if (!waitingWorker) {
      window.location.reload();
      return;
    }
    waitingWorker.postMessage({ type: "SKIP_WAITING" });
    setTimeout(() => window.location.reload(), 100);
  }, [waitingWorker]);

  return { needsUpdate, applyUpdate };
}
