// LocalStorage-backed reactive hooks for alerts and price snapshots.
// (The per-item notes feature was removed; only alerts and snapshots remain.)
import { useEffect, useState, useCallback } from "react";

const ALERTS_KEY = "castia.alerts";
export const ALERTS_EVENT = "castia:alerts";
const ALERTS_STORE = {
  read: () => {
    try {
      const raw = localStorage.getItem(ALERTS_KEY);
      return raw ? JSON.parse(raw) : {};
    } catch { return {}; }
  },
  write: (obj) => {
    try {
      localStorage.setItem(ALERTS_KEY, JSON.stringify(obj));
      window.dispatchEvent(new CustomEvent(ALERTS_EVENT));
    } catch { /* quota */ }
  },
};

const SNAPSHOTS_KEY = "castia.snapshots";
const SNAPSHOT_BUCKETS = [
  { label: "1h", maxAgeMs: 1 * 60 * 60 * 1000 },
  { label: "6h", maxAgeMs: 6 * 60 * 60 * 1000 },
  { label: "24h", maxAgeMs: 24 * 60 * 60 * 1000 },
  { label: "7d", maxAgeMs: 7 * 24 * 60 * 60 * 1000 },
];

function readSnapshots() {
  try {
    const raw = localStorage.getItem(SNAPSHOTS_KEY);
    return raw ? JSON.parse(raw) : [];
  } catch { return []; }
}
function writeSnapshots(arr) {
  try { 
    // Prune entries older than 30 days before saving to keep localStorage healthy.
    const cutoff = Date.now() - 30 * 24 * 60 * 60 * 1000;
    const pruned = arr.filter(s => s.ts > cutoff).slice(-100);
    localStorage.setItem(SNAPSHOTS_KEY, JSON.stringify(pruned)); 
  } catch {}
}

export function loadRollingSnapshots() {
  return readSnapshots();
}

export function writeRollingSnapshot(snap) {
  const now = Date.now();
  const entry = { ...snap, ts: now };
  writeSnapshots([...readSnapshots(), entry]);
}

export function getSnapshotsByAge(maxAgeMs) {
  const now = Date.now();
  return readSnapshots().filter(s => (now - s.ts) <= maxAgeMs);
}

export function getSnapshotStats() {
  return SNAPSHOT_BUCKETS.map(b => ({
    label: b.label,
    count: getSnapshotsByAge(b.maxAgeMs).length,
  }));
}

// Per-item price alerts: { itemKey: { kind: "below"|"above", value: number } }
export function useAlerts() {
  const [map, setMap] = useState(ALERTS_STORE.read);
  useEffect(() => {
    const h = () => setMap(ALERTS_STORE.read());
    window.addEventListener(ALERTS_EVENT, h);
    window.addEventListener("storage", h);
    return () => {
      window.removeEventListener(ALERTS_EVENT, h);
      window.removeEventListener("storage", h);
    };
  }, []);
  const set = useCallback((itemKey, alert) => {
    setMap((prev) => {
      const next = { ...prev };
      if (!alert) delete next[itemKey];
      else next[itemKey] = alert;
      ALERTS_STORE.write(next);
      return next;
    });
  }, []);
  const get = useCallback((itemKey) => map[itemKey] || null, [map]);
  return { get, set, all: map, count: Object.keys(map).length };
}

// Price snapshot for "what changed since last visit"
const SNAPSHOT_KEY = "castia.snapshot";
const SNAPSHOT_SEEN_KEY = "castia.snapshot.seen";
export function loadSnapshot() {
  try {
    const raw = localStorage.getItem(SNAPSHOT_KEY);
    return raw ? JSON.parse(raw) : null;
  } catch { return null; }
}
export function writeSnapshot(snap) {
  try { localStorage.setItem(SNAPSHOT_KEY, JSON.stringify(snap)); } catch {}
}
export function markSnapshotSeen() {
  try { localStorage.setItem(SNAPSHOT_SEEN_KEY, Date.now().toString()); } catch {}
}
export function lastSeenAt() {
  try {
    const v = localStorage.getItem(SNAPSHOT_SEEN_KEY);
    return v ? Number(v) : 0;
  } catch { return 0; }
}

// Full market + sellers cache for offline fallback (Phase 8.3).
// Distinct from the snapshot above: the snapshot is just medians
// (for diff), this stores the full processed rows so the entire app
// can render from cache when the Worker is unreachable.
const PRICE_CACHE_KEY = "castia.cache.prices";
const SELLERS_CACHE_KEY = "castia.cache.sellers";
const CACHE_TTL_MS = 7 * 24 * 60 * 60 * 1000;
const CACHE_SCHEMA_VERSION = 1;

// Schema validators keyed by cache key. Return true if the data shape
// is usable for rehydration.
const VALIDATORS = {
  [PRICE_CACHE_KEY]: (data) =>
    data !== null &&
    typeof data === "object" &&
    Array.isArray(data.rows),
  [SELLERS_CACHE_KEY]: (data) =>
    Array.isArray(data),
};

function readCache(key) {
  try {
    const raw = localStorage.getItem(key);
    if (!raw) return null;
    const parsed = JSON.parse(raw);
    if (!parsed?.at || !parsed?.data) { localStorage.removeItem(key); return null; }
    // Schema version mismatch — the data shape may have changed.
    if (parsed.schema !== CACHE_SCHEMA_VERSION) { localStorage.removeItem(key); return null; }
    // Drop stale-by-age caches so a long-dormant tab doesn't pretend
    // to have fresh data forever.
    if (Date.now() - parsed.at > CACHE_TTL_MS) { localStorage.removeItem(key); return null; }
    // Validate the payload shape before returning.
    const validator = VALIDATORS[key];
    if (validator && !validator(parsed.data)) { localStorage.removeItem(key); return null; }
    return parsed;
  } catch { return null; }
}
function writeCache(key, data) {
  try { localStorage.setItem(key, JSON.stringify({ at: Date.now(), data, schema: CACHE_SCHEMA_VERSION })); } catch {}
}

export function loadPriceCache() { return readCache(PRICE_CACHE_KEY); }
export function writePriceCache(processed) { writeCache(PRICE_CACHE_KEY, processed); }
export function loadSellersCache() { return readCache(SELLERS_CACHE_KEY); }
export function writeSellersCache(processed) { writeCache(SELLERS_CACHE_KEY, processed); }
