import { useEffect, useState } from "react";
import { createPortal } from "react-dom";
import { X, Keyboard } from "lucide-react";
import { CMD_KEY_CHIP, CMD_KEY_LABEL } from "@/lib/platform";

const SHORTCUTS = [
  { keys: ["?"],            desc: "Open this help" },
  { keys: [CMD_KEY_CHIP, "k"], desc: `Open command palette (${CMD_KEY_LABEL}+K)` },
  { keys: ["/"],            desc: "Focus search" },
  { keys: ["j", "↓"],       desc: "Next row" },
  { keys: ["k", "↑"],       desc: "Previous row" },
  { keys: ["Enter"],        desc: "Open selected item" },
  { keys: ["f"],            desc: "Toggle favorite" },
  { keys: ["c"],            desc: "Toggle compare" },
  { keys: ["Esc"],          desc: "Close drawer / dialog" },
];

export default function KeyboardHelpModal() {
  const [open, setOpen] = useState(false);

  useEffect(() => {
    const onKey = (e) => {
      const target = e.target;
      const isTyping = target && (target.tagName === "INPUT" || target.tagName === "TEXTAREA" || target.isContentEditable);
      if (isTyping) return;
      if (e.key === "?" || (e.shiftKey && e.key === "/")) {
        e.preventDefault();
        setOpen((o) => !o);
      } else if (e.key === "Escape" && open) {
        e.preventDefault();
        setOpen(false);
      }
    };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, [open]);

  if (!open) return null;

  return createPortal(
    <div
      data-testid="kbd-help-modal"
      className="fixed inset-0 z-[200] grid place-items-center bg-black/70 backdrop-blur-sm"
      onClick={() => setOpen(false)}
    >
      <div
        className="relative w-[min(92vw,520px)] bg-bg-base border border-white/10 rounded-2xl shadow-2xl overflow-hidden"
        onClick={(e) => e.stopPropagation()}
      >
        <div className="flex items-center justify-between p-5 border-b border-white/5">
          <div className="flex items-center gap-2">
            <Keyboard className="w-4 h-4 text-emerald-400" />
            <h2 className="font-heading text-base font-bold uppercase tracking-[0.18em]">Keyboard shortcuts</h2>
          </div>
          <button onClick={() => setOpen(false)} aria-label="Close help" className="text-zinc-500 hover:text-white transition-colors">
            <X className="w-4 h-4" />
          </button>
        </div>
        <ul className="p-5 grid gap-2.5 max-h-[70vh] overflow-y-auto">
          {SHORTCUTS.map((s, i) => (
            <li key={i} className="flex items-center justify-between gap-4 py-1.5">
              <span className="text-zinc-300 text-sm">{s.desc}</span>
              <span className="inline-flex items-center gap-1 shrink-0">
                {s.keys.map((k, j) => (
                  <kbd key={j} className="kbd">{k}</kbd>
                ))}
              </span>
            </li>
          ))}
        </ul>
        <div className="px-5 py-3 border-t border-white/5 text-zinc-600 text-[11px] font-mono uppercase tracking-wider text-center">
          Press <kbd className="kbd">?</kbd> anytime to toggle this
        </div>
      </div>
    </div>,
    document.body
  );
}
