import { useState } from "react";
import { useSearchParams, Link } from "react-router-dom";
import { AnimatePresence, motion, useReducedMotion } from "framer-motion";
import { X, GitCompare, ChevronUp, ChevronDown, ArrowRight, ExternalLink } from "lucide-react";
import { useCompare } from "@/lib/useFavorites";
import { useMarket } from "@/lib/MarketContext";
import { fmt } from "@/lib/parseItem";
import { openItem } from "./DetailDrawer";
import ItemName from "./ItemName";

const ConfDot = ({ conf }) => {
  const map = { high: "bg-emerald-400", good: "bg-lime-400", fair: "bg-amber-400", low: "bg-orange-400", unreliable: "bg-zinc-600" };
  return <span className={`inline-block w-1.5 h-1.5 rounded-full ${map[conf] || "bg-zinc-600"}`}></span>;
};

export default function CompareTray() {
  const compare = useCompare();
  const { market } = useMarket();
  const [open, setOpen] = useState(false);
  const [searchParams, setSearchParams] = useSearchParams();
  const prefersReduced = useReducedMotion();

  if (compare.count === 0) return null;

  const items = (market?.rows || []).filter((r) => compare.has(r.key));

  if (prefersReduced) {
    return (
      <>
        <div className="fixed bottom-6 left-1/2 -translate-x-1/2 sm:left-6 sm:translate-x-0 z-40">
          <button
            data-testid="compare-tray-toggle"
            onClick={() => setOpen((s) => !s)}
            className="inline-flex items-center gap-3 bg-emerald-500 hover:bg-emerald-400 text-black font-bold uppercase tracking-[0.18em] text-xs px-5 py-3.5 rounded-full shadow-[0_8px_32px_rgba(16,185,129,0.4)] transition-all active:scale-95"
          >
            <GitCompare className="w-4 h-4" />
            Compare ({compare.count})
            {open ? <ChevronDown className="w-4 h-4" /> : <ChevronUp className="w-4 h-4" />}
          </button>
        </div>

        {open && (
          <div
            data-testid="compare-tray-drawer"
            className="fixed bottom-24 left-6 right-6 sm:right-auto sm:w-[min(760px,92vw)] z-40 bg-bg-deeper border border-emerald-500/30 rounded-2xl shadow-[0_30px_80px_rgba(0,0,0,0.7)]"
          >
            <div className="flex items-center justify-between px-5 py-4 border-b border-white/10">
              <div className="flex items-center gap-2">
                <GitCompare className="w-4 h-4 text-emerald-400" />
                <span className="font-heading font-bold">Compare</span>
                <span className="font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500">
                  {compare.count}/{compare.max}
                </span>
              </div>
              <div className="flex items-center gap-2">
                <Link
                  to="/compare"
                  onClick={() => setOpen(false)}
                  data-testid="compare-open-page"
                  className="font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-400 hover:text-emerald-400 inline-flex items-center gap-1 transition-colors"
                >
                  <ExternalLink className="w-3 h-3" /> Open page
                </Link>
                <button
                  data-testid="compare-clear"
                  onClick={() => compare.clear()}
                  className="font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500 hover:text-red-400 transition-colors"
                >
                  Clear
                </button>
                <button
                  onClick={() => setOpen(false)}
                  className="p-1 text-zinc-500 hover:text-white transition-colors"
                  aria-label="Close"
                >
                  <X className="w-4 h-4" />
                </button>
              </div>
            </div>

            <div className="overflow-x-auto max-h-[40vh] no-scrollbar">
              <table className="w-full text-sm">
                <thead>
                  <tr className="text-left font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500 border-b border-white/5">
                    <th className="px-5 py-3 font-medium">Item</th>
                    <th className="px-5 py-3 font-medium text-right">Median</th>
                    <th className="px-5 py-3 font-medium text-right hidden sm:table-cell">IQR</th>
                    <th className="px-5 py-3 font-medium hidden sm:table-cell">Conf.</th>
                    <th className="px-5 py-3 font-medium w-10"></th>
                  </tr>
                </thead>
                <tbody>
                  {items.length === 0 ? (
                    <tr><td colSpan={5} className="px-5 py-8 text-center text-zinc-500 font-mono text-xs">Loading&hellip;</td></tr>
                  ) : items.map((r) => (
                    <tr key={r.key} className="border-b border-white/5 last:border-0 hover:bg-white/[0.03] transition-colors">
                      <td className="px-5 py-3">
                        <button
                          onClick={() => { openItem(searchParams, setSearchParams, r.key); setOpen(false); }}
                          className="font-medium text-white hover:text-emerald-400 transition-colors text-left block max-w-full"
                        >
                          <ItemName name={r.name} tier={r.tier} modifiers={r.modifiers} layout="wrap" />
                        </button>
                        <div className="text-[10px] text-zinc-500 font-mono mt-0.5">{r.category}</div>
                      </td>
                      <td className="px-5 py-3 font-mono text-right text-white tabular">{fmt(r.median)}</td>
                      <td className="px-5 py-3 font-mono text-right text-zinc-400 hidden sm:table-cell text-xs tabular">
                        {fmt(r.iqrLow)}&ndash;{fmt(r.iqrHigh)}
                      </td>
                      <td className="px-5 py-3 hidden sm:table-cell">
                        <span className="inline-flex items-center gap-1.5 font-mono text-xs text-zinc-400">
                          <ConfDot conf={r.confidence} /> {r.confidence}
                        </span>
                      </td>
                      <td className="px-5 py-3 text-right">
                        <button
                          onClick={() => compare.toggle(r.key)}
                          className="text-zinc-500 hover:text-red-400 transition-colors p-1"
                          aria-label="Remove"
                        >
                          <X className="w-3.5 h-3.5" />
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            <div className="px-5 py-3 border-t border-white/10 flex items-center justify-between font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500">
              <span>Tap an item to view detail</span>
              <button
                onClick={() => { setOpen(false); }}
                className="inline-flex items-center gap-1 text-emerald-400 hover:text-emerald-300"
              >
                Close <ArrowRight className="w-3 h-3" />
              </button>
            </div>
          </div>
        )}
      </>
    );
  }

  return (
    <>
      <AnimatePresence>
        <motion.div
          key="tray"
          initial={{ y: 100, opacity: 0, scale: 0.9 }}
          animate={{ y: 0, opacity: 1, scale: 1 }}
          exit={{ y: 100, opacity: 0, scale: 0.9 }}
          transition={{ type: "spring", stiffness: 220, damping: 18 }}
          className="fixed bottom-6 left-1/2 -translate-x-1/2 sm:left-6 sm:translate-x-0 z-40"
        >
          <button
            data-testid="compare-tray-toggle"
            onClick={() => setOpen((s) => !s)}
            className="inline-flex items-center gap-3 bg-emerald-500 hover:bg-emerald-400 text-black font-bold uppercase tracking-[0.18em] text-xs px-5 py-3.5 rounded-full shadow-[0_8px_32px_rgba(16,185,129,0.4)] transition-all active:scale-95"
          >
            <GitCompare className="w-4 h-4" />
            Compare ({compare.count})
            {open ? <ChevronDown className="w-4 h-4" /> : <ChevronUp className="w-4 h-4" />}
          </button>
        </motion.div>
      </AnimatePresence>

      <AnimatePresence>
        {open && (
          <motion.div
            key="drawer"
            initial={{ opacity: 0, y: 40 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: 40 }}
            transition={{ duration: 0.4, ease: [0.16, 1, 0.3, 1] }}
            data-testid="compare-tray-drawer"
            className="fixed bottom-24 left-6 right-6 sm:right-auto sm:w-[min(760px,92vw)] z-40 bg-bg-deeper border border-emerald-500/30 rounded-2xl shadow-[0_30px_80px_rgba(0,0,0,0.7)]"
          >
            <div className="flex items-center justify-between px-5 py-4 border-b border-white/10">
              <div className="flex items-center gap-2">
                <GitCompare className="w-4 h-4 text-emerald-400" />
                <span className="font-heading font-bold">Compare</span>
                <span className="font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500">
                  {compare.count}/{compare.max}
                </span>
              </div>
              <div className="flex items-center gap-2">
                <Link
                  to="/compare"
                  onClick={() => setOpen(false)}
                  data-testid="compare-open-page"
                  className="font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-400 hover:text-emerald-400 inline-flex items-center gap-1 transition-colors"
                >
                  <ExternalLink className="w-3 h-3" /> Open page
                </Link>
                <button
                  data-testid="compare-clear"
                  onClick={() => compare.clear()}
                  className="font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500 hover:text-red-400 transition-colors"
                >
                  Clear
                </button>
                <button
                  onClick={() => setOpen(false)}
                  className="p-1 text-zinc-500 hover:text-white transition-colors"
                  aria-label="Close"
                >
                  <X className="w-4 h-4" />
                </button>
              </div>
            </div>

            <div className="overflow-x-auto max-h-[40vh] no-scrollbar">
              <table className="w-full text-sm">
                <thead>
                  <tr className="text-left font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500 border-b border-white/5">
                    <th className="px-5 py-3 font-medium">Item</th>
                    <th className="px-5 py-3 font-medium text-right">Median</th>
                    <th className="px-5 py-3 font-medium text-right hidden sm:table-cell">IQR</th>
                    <th className="px-5 py-3 font-medium hidden sm:table-cell">Conf.</th>
                    <th className="px-5 py-3 font-medium w-10"></th>
                  </tr>
                </thead>
                <tbody>
                  {items.length === 0 ? (
                    <tr><td colSpan={5} className="px-5 py-8 text-center text-zinc-500 font-mono text-xs">Loading&hellip;</td></tr>
                  ) : items.map((r) => (
                    <tr key={r.key} className="border-b border-white/5 last:border-0 hover:bg-white/[0.03] transition-colors">
                      <td className="px-5 py-3">
                        <button
                          onClick={() => { openItem(searchParams, setSearchParams, r.key); setOpen(false); }}
                          className="font-medium text-white hover:text-emerald-400 transition-colors text-left block max-w-full"
                        >
                          <ItemName name={r.name} tier={r.tier} modifiers={r.modifiers} layout="wrap" />
                        </button>
                        <div className="text-[10px] text-zinc-500 font-mono mt-0.5">{r.category}</div>
                      </td>
                      <td className="px-5 py-3 font-mono text-right text-white tabular">{fmt(r.median)}</td>
                      <td className="px-5 py-3 font-mono text-right text-zinc-400 hidden sm:table-cell text-xs tabular">
                        {fmt(r.iqrLow)}&ndash;{fmt(r.iqrHigh)}
                      </td>
                      <td className="px-5 py-3 hidden sm:table-cell">
                        <span className="inline-flex items-center gap-1.5 font-mono text-xs text-zinc-400">
                          <ConfDot conf={r.confidence} /> {r.confidence}
                        </span>
                      </td>
                      <td className="px-5 py-3 text-right">
                        <button
                          onClick={() => compare.toggle(r.key)}
                          className="text-zinc-500 hover:text-red-400 transition-colors p-1"
                          aria-label="Remove"
                        >
                          <X className="w-3.5 h-3.5" />
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            <div className="px-5 py-3 border-t border-white/10 flex items-center justify-between font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500">
              <span>Tap an item to view detail</span>
              <button
                onClick={() => { setOpen(false); }}
                className="inline-flex items-center gap-1 text-emerald-400 hover:text-emerald-300"
              >
                Close <ArrowRight className="w-3 h-3" />
              </button>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
}
